drop table if exists award;
create table award (
  award_id integer,
  organization text,
  year integer,
  award_category text,
  award text,
  person text,
  role text,
  episode_id text,
  season integer,
  song text,
  result text
);


drop table if exists character_award;
create table character_award (
  award_id integer,
  character text
);



drop table if exists episode;
create table episode (
  episode_id text,
  season integer,
  episode integer,
  number_in_series integer,
  title text,
  summary text,
  air_date date,
  episode_image text,
  rating double precision,
  votes integer
);


drop table if exists keyword;
create table keyword (
  episode_id text,
  keyword text
);


drop table if exists person;
create table person (
  name text,
  birthdate date,
  birth_name text,
  birth_place text,
  birth_region text,
  birth_country text,
  height_meters double precision,
  nickname text
);


drop table if exists vote;
create table vote (
  episode_id text,
  stars integer,
  votes integer,
  percent double precision
);




drop table if exists credit;
create table credit (
  episode_id text,
  category text,
  person text,
  role text,
  credited boolean
);

